function sequentialDigits(low, high) {
    const result = [];
    for (let i = 1; i <= 9; ++i) {
        let number = i;
        for (let j = i + 1; j <= 9; ++j) {
            number = number * 10 + j;
            if (number >= low && number <= high) {
                result.push(number);
            }
        }
    }
    return result.sort((a, b) => a - b);
}
